package linker

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/buildpack"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/inspector"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/linker"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type ResolverProxy struct {
	linker.UnimplementedResolverServer
	client linker.ResolverClient
}

func init() {
	proxyutil.Register(&linker.Resolver_ServiceDesc, NewResolverProxy)
}
func NewResolverProxy(cc grpc.ClientConnInterface) linker.ResolverServer {
	return &ResolverProxy{client: linker.NewResolverClient(cc)}
}
func (p *ResolverProxy) RegisterPlugins(ctx context.Context, in *inspector.InspectorDescriptions) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[inspector.InspectorDescriptions, emptypb.Empty](p.client.RegisterPlugins)(ctx, in)
}
func (p *ResolverProxy) Resolve(ctx context.Context, in *runtime.PackageQuery) (*linker.Resolution, error) {
	return proxyutil.ProxyMethod[runtime.PackageQuery, linker.Resolution](p.client.Resolve)(ctx, in)
}
func (p *ResolverProxy) RegisterBundle(ctx context.Context, in *buildpack.Bundle) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[buildpack.Bundle, emptypb.Empty](p.client.RegisterBundle)(ctx, in)
}
